SELECT DISTINCT m.person_id
FROM mentions m
JOIN sentiment s ON m.mention_id = s.mention_id;

SELECT AVG(mentions_count) AS avg_mentions_count
FROM mentions
WHERE source_id = 1;

SELECT mention_id, source_id, tone_avg, engagement_count
FROM mentions
WHERE mention_id = 0;

SELECT DISTINCT person_id 
FROM mentions 
ORDER BY created_at DESC;
